import{_ as i,c as e,a as n,o as a}from"./app-CEcM0piI.js";const l={};function t(d,s){return a(),e("div",null,s[0]||(s[0]=[n(`<p>MySQL数据库是一个典型的C/S结构，即：客户端和服务器端。如果我们部署好了MySQL服务器，想要在客户端访问服务器端的数据，在编写程序的时候就可以通过官方提供的C语言的API来实现。</p><p>编译时要在末尾加上选项连接到mysql的动态库</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>gcc -o $@ $^ -lmysqlclient</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>数据库开发时出错不能使用perror打印,这是mysql的错误不会写到系统错误中</p><ol><li>创建数据库对象 分配或初始化MYSQL结构体。</li></ol><ul><li>mysql: MYSQL对象, 如果是NULL指针，将分配、初始化、并返回新对象。否则，将初始化对象，并返回对象的地址。</li><li>return: 成功返回指向MYSQL对象的指针, 失败: 当内存不足以分配新对象时返回NULL</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>MYSQL* mysql_init(MYSQL* mysql);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>连接数据库 连接到指定的数据库对象</li></ol><ul><li>mysql: 要连接的MYSQL对象</li><li>host: 打开该数据库主机的ip地址,通常填127.0.0.1本地主机名</li><li>user: 要以哪个数据库用户的身份打开数据库的用户名</li><li>passwd: 用户名对应的密码</li><li>db: 要登陆的数据库名</li><li>port: 通常填0为默认端口,(mysql也通常为3306)</li><li>unix_socket: 套接字,默认填NULL不用</li><li>client_flag:客户端标志,一般填0</li><li>return: 如果连接成功返回指向MYSQL的指针(和mysql参数一样),失败返回NULL</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>MYSQL* mysql_real_connect(</span></span>
<span class="line"><span>	MYSQL* mysql,</span></span>
<span class="line"><span>	const char* host,</span></span>
<span class="line"><span>	const char* user,</span></span>
<span class="line"><span>	const char* passwd,</span></span>
<span class="line"><span>	const char* db,</span></span>
<span class="line"><span>	unsigned int port,</span></span>
<span class="line"><span>	const char* unix_socket,</span></span>
<span class="line"><span>	unsigned long client_flag);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>执行sql语句 执行传入的sql语句</li></ol><ul><li>mysql: 要执行语句的MYSQL对象</li><li>query: 字符串类型的sql语句结尾不需要添加;</li><li>return: 成功返回0, 失败返回非0值. 如果是查询, 结果集在mysql 对象中</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int mysql_query(MYSQL* mysql, const char* query)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="4"><li>取回结果集</li></ol><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>typedef struct st_mysql_res{</span></span>
<span class="line"><span>	my_ulonglong row_count;</span></span>
<span class="line"><span>	MYSQL_FIELD* fields;</span></span>
<span class="line"><span>	MYSQL DATA* data;</span></span>
<span class="line"><span>	MYSQL_ROWS* data_cursor;</span></span>
<span class="line"><span>	unsigned long* lengths;    /* column lengths of current row */</span></span>
<span class="line"><span>	MYSQL* handle;    /* for unbuffered reads */</span></span>
<span class="line"><span>	const struct st_mysql_methods* methods;</span></span>
<span class="line"><span>	MYSQL_ROW row    /* If unbuffered road */*</span></span>
<span class="line"><span>	MYSQL_ROW current_row;    /* buffer to current row */</span></span>
<span class="line"><span>	MEM_ROOT field_alloc;</span></span>
<span class="line"><span>	unsigned int field_count,current_field;</span></span>
<span class="line"><span>	my_bool eof;    /* Used by mysql_fetch_row */</span></span>
<span class="line"><span>	/* mysql_stmt_close() had to cancel this result */</span></span>
<span class="line"><span>	my_bool unbuffered_fetch_cancelled;</span></span>
<span class="line"><span>	void* extension;</span></span>
<span class="line"><span>}MYSQL_RES;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>取回完整的结果集</p><ul><li>mysql: 要取结果的MYSQL对象</li><li>return: MYSQL_RES对象指针,</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>MYSQL_RES *mysql_store_result(MYSQL* mysql)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="5"><li>获取数据</li></ol><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>// mysql.h</span></span>
<span class="line"><span>// 结果集中的每一个列对应一个 MYSQL_FIELD</span></span>
<span class="line"><span>typedef struct st_mysql_field {</span></span>
<span class="line"><span>  char *name;                 /* 列名-&gt; 字段的名字 */</span></span>
<span class="line"><span>  char *org_name;             /* Original column name, if an alias */</span></span>
<span class="line"><span>  char *table;                /* Table of column if column was a field */</span></span>
<span class="line"><span>  char *org_table;            /* Org table name, if table was an alias */</span></span>
<span class="line"><span>  char *db;                   /* Database for table */</span></span>
<span class="line"><span>  char *catalog;              /* Catalog for table */</span></span>
<span class="line"><span>  char *def;                  /* Default value (set by mysql_list_fields) */</span></span>
<span class="line"><span>  unsigned long length;       /* Width of column (create length) */</span></span>
<span class="line"><span>  unsigned long max_length;   /* Max width for selected set */</span></span>
<span class="line"><span>  unsigned int name_length;</span></span>
<span class="line"><span>  unsigned int org_name_length;                                                                                        </span></span>
<span class="line"><span>  unsigned int table_length;</span></span>
<span class="line"><span>  unsigned int org_table_length;</span></span>
<span class="line"><span>  unsigned int db_length;</span></span>
<span class="line"><span>  unsigned int catalog_length;</span></span>
<span class="line"><span>  unsigned int def_length;</span></span>
<span class="line"><span>  unsigned int flags;         /* Div flags */</span></span>
<span class="line"><span>  unsigned int decimals;      /* Number of decimals in field */</span></span>
<span class="line"><span>  unsigned int charsetnr;     /* Character set */</span></span>
<span class="line"><span>  enum enum_field_types type; /* Type of field. See mysql_com.h for types */</span></span>
<span class="line"><span>  void *extension;</span></span>
<span class="line"><span>} MYSQL_FIELD;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>获取结果集中数据的行数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int mysql_num_rows(MYSQL_RES &amp;res)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>从结果集中获取下一行</p><ul><li>result: 要获取的结果集对象</li><li>return: 成功得到了当前记录中每个字段的值,失败:NULL, 说明数据已经读完了</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>MYSQL_ROW mysql_fetch_row(MYSQL_RES* result)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>MYSQL_ROW是一个<code>char**</code>类型,可以遍历直接打印一行的数据,也可以对这个二维数组再次取索引获取每个属性的值</p><p>得到结果集的列数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>unsigned int mysql_num_fields(MYSQL_RES *result)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>得到结果集中所有列的名字 返回MYSQL_FIELD* 指向一个结构体</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>MYSQL_FIELD *mysql_fetch_fields(MYSQL_RES *result);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>返回结果集内当前行的列的长度:</p><ol><li>如果打算复制字段值，使用该函数能避免调用strlen()。</li><li>如果结果集包含二进制数据，必须使用该函数来确定数据的大小，原因在于，对于包含Null字符的任何字段，strlen()将返回错误的结果。</li></ol><ul><li>result: 通过查询得到的结果集</li><li>return:无符号长整数的数组表示各列的大小。如果出现错误，返回NULL。</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>unsigned long *mysql_fetch_lengths(MYSQL_RES *result);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="6"><li>释放结果集 获取结果集后必须使用指定函数释放结果集</li></ol><ul><li>result: 要释放的结果集对象</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>void mysql_free_result(MYSQL_RES* result)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="7"><li>关闭数据库的连接</li></ol><ul><li>mysql: 要关闭的数据库对象</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>void mysql_close(MYSQL* mysql)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>字符编码</strong> 获取api默认使用的字符编码 为当前连接返回默认的字符集。</p><ul><li>返回值: 默认字符集的名称。</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const char *mysql_character_set_name(MYSQL *mysql)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>设置api使用的字符集 第二个参数 csname 就是要设置的字符集 -&gt; 支持中文: utf8</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>int mysql_set_character_set(MYSQL *mysql, char *csname);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>事务</strong> mysql中默认会进行事务的提交 因为自动提交事务, 会对我们的操作造成影响 如果我们操作的步骤比较多, 集合的开始和结束需要用户自己去设置, 需要改为手动方式提交事务</p><p>设置自动提交模式</p><ul><li>mode: 如果模式为“1”，启用autocommit模式；如果模式为“0”，禁止autocommit模式。</li><li>return: 如果成功，返回0，如果出现错误，返回非0值。</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>my_bool mysql_autocommit(MYSQL *mysql, my_bool mode)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>事务提交 返回值: 成功: 0, 失败: 非0</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>my_bool mysql_commit(MYSQL *mysql);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>数据回滚 返回值: 成功: 0, 失败: 非0</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>my_bool mysql_rollback(MYSQL *mysql)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>打印错误信息</strong> 返回错误的描述</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const char *mysql_error(MYSQL *mysql);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>返回错误的编号</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>unsigned int mysql_errno(MYSQL *mysql);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="部分api函数表" tabindex="-1"><a class="header-anchor" href="#部分api函数表"><span>部分API函数表</span></a></h4><table><thead><tr><th>函数</th><th>作用描述</th></tr></thead><tbody><tr><td>mysql_init()</td><td>获取或初始化MYSQL结构。</td></tr><tr><td>mysql_real_connect()</td><td>连接到MySQL服务器。</td></tr><tr><td>mysql_query()</td><td>执行指定为“以Null终结的字符串”的SQL查询。</td></tr><tr><td>mysql_store_result()</td><td>检索完整的结果集至客户端。</td></tr><tr><td>mysql_use_result()</td><td>初始化逐行的结果集检索</td></tr><tr><td>mysql_fetch_field()</td><td>返回下一个表字段的类型。</td></tr><tr><td>mysql_fetch_fields()</td><td>返回所有字段结构的数组。</td></tr><tr><td>mysql_fetch_lengths()</td><td>返回当前行中所有列的长度。</td></tr><tr><td>mysql_fetch_row()</td><td>从结果集中获取下一行</td></tr><tr><td>mysql_field_count()</td><td>返回上次执行语句的结果列的数目。</td></tr><tr><td>mysql_free_result()</td><td>释放结果集使用的内存。</td></tr><tr><td>mysql_close()</td><td>关闭服务器连接。</td></tr><tr><td>mysql_autocommit()</td><td>切换 autocommit模式，ON/OFF</td></tr><tr><td>mysql_commit()</td><td>提交事务。</td></tr><tr><td>mysql_errno()</td><td>返回上次调用的MySQL函数的错误编号</td></tr><tr><td>mysql_error()</td><td>返回上次调用的MySQL函数的错误消息</td></tr><tr><td>mysql_options()</td><td>为mysql_connect()设置连接选项。</td></tr><tr><td>mysql_ping()</td><td>检查与服务器的连接是否工作，如有必要重新连接。</td></tr></tbody></table>`,59)]))}const c=i(l,[["render",t]]),p=JSON.parse('{"path":"/tools/mysql/7/","title":"7 C语言API","lang":"zh-CN","frontmatter":{"title":"7 C语言API","createTime":"2025/04/05 12:12:26","permalink":"/tools/mysql/7/"},"readingTime":{"minutes":5.36,"words":1609},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/MySQL/7 C语言API.md","headers":[]}');export{c as comp,p as data};
